import sqlite3
import os

def popuni_riznicu():
    db_path = 'mitologija.db'
    #if os.path.exists(db_path):
    #    os.remove(db_path)
    
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE bica (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            ime TEXT NOT NULL,
            opis TEXT NOT NULL,
            slika TEXT,
            kategorija TEXT,
            opasnost INTEGER
        )
    ''')

    # ПРВИХ 20 БИЋА СА ДЕТАЉНИМ ОПИСИМА
